function chooseReplacement(id){const input=document.createElement('input');input.type='file';input.accept=ALLOWED_PHOTO_TYPES.join(',');input.addEventListener('change',()=>{const file=input.files?.[0];if(file)photoProcessingQueue=photoProcessingQueue.then(()=>replacePhoto(id,file));},{once:true});input.click();}
async function replacePhoto(id,original){const index=photos.findIndex(photo=>photo.id===id);if(index<0)return;setPhotoBusy(true);photoStatus.textContent=`Optimizando fotografía ${index+1} de ${photos.length}`;try{validateOriginalPhoto(original);const optimized=await optimizePhoto(original),otherBytes=finalPhotoBytes()-photos[index].file.size;if(otherBytes+optimized.file.size>MAX_FINAL_TOTAL_PHOTO_BYTES)throw new Error('El peso final acumulado superaría 20 MB.');URL.revokeObjectURL(photos[index].url);photos[index]={...photos[index],file:optimized.file,originalFile:original,url:URL.createObjectURL(optimized.file),originalName:original.name,originalSize:optimized.originalSize,optimizedSize:optimized.optimizedSize,width:optimized.width,height:optimized.height};photoStatus.textContent='Fotografía reemplazada y optimizada correctamente.';if(gpsConsent.checked)await analyzePhotoGps();}catch(error){photoStatus.textContent=error?.message||'No pudimos optimizar la fotografía de reemplazo.';}finally{setPhotoBusy(false);renderPhotos();updateLocationWarning();}}

function hasConfirmedLocation(){return isValidGoogleMapsLink(mapsLink.value)||hasPrivateCoordinates(gpsCoordinates);}
function updatePhotoGpsOffer(){const option=gpsConsent.closest('.gps-consent'),available=photos.length>0&&!hasConfirmedLocation()&&visualAnalysisAllowed();option.hidden=!available;gpsConsent.disabled=!available;if(!available&&gpsConsent.checked)gpsConsent.checked=false;if(!photos.length)gpsStatus.textContent='';else if(hasConfirmedLocation())gpsStatus.textContent='Ya indicaste una ubicación; no necesitamos buscar GPS en las fotografías.';else if(!visualAnalysisAllowed())gpsStatus.textContent='La extracción automática de ubicación por GPS de fotografías es un beneficio exclusivo de los planes superiores.';}
function currentLocationMissing(){return locationIsMissing({mapsLink:mapsLink.value,confirmedCoordinates:gpsCoordinates});}
function updateLocationWarning(){const validLink=isValidGoogleMapsLink(mapsLink.value);if(validLink){locationWarningDismissed=false;lastMapsLinkValid=true;}else if(lastMapsLinkValid){locationWarningDismissed=false;lastMapsLinkValid=false;}const missing=currentLocationMissing();locationWarning.hidden=!shouldShowLocationWarning({mapsLink:mapsLink.value,confirmedCoordinates:gpsCoordinates,gpsAnalysisPending,evaluationReady:locationEvaluationReady,dismissed:locationWarningDismissed});const summary=document.querySelector('#location-summary-warning');if(summary)summary.hidden=!missing;updatePhotoGpsOffer();return missing;}
async function analyzePhotoGps(){if(hasConfirmedLocation()){gpsConsent.checked=false;gpsAnalysisPending=false;gpsStatus.textContent='Ya indicaste una ubicación; no reemplazaremos esa información.';updateLocationWarning();return;}if(!gpsConsent.checked){gpsAnalysisPending=false;gpsStatus.textContent='No autorizaste el análisis GPS. Puedes agregar una ubicación o continuar sin ella.';updateLocationWarning();return;}gpsAnalysisPending=true;gpsStatus.textContent='Buscando ubicación GPS privada en las fotografías…';updateLocationWarning();const coordinates=await findFirstPhotoGps(photos.map(photo=>photo.originalFile).filter(Boolean));if(hasPrivateCoordinates(coordinates)){gpsCoordinates=coordinates;locationSource='photo_exif';locationConfirmedAt=new Date().toISOString();mapsLink.value=coordinatesToGoogleMapsLink(coordinates);mapsLink.dispatchEvent(new Event('input',{bubbles:true}));}gpsAnalysisPending=false;gpsStatus.textContent=gpsCoordinates?'Encontramos una ubicación GPS. Se guardará de forma privada y solo se mostrará una referencia aproximada.':'Las fotografías seleccionadas no contienen una ubicación GPS utilizable.';updateLocationWarning();}
function openLocationHelp(){locationHelpReturnFocus=document.activeElement;if(typeof locationHelpDialog.showModal==='function')locationHelpDialog.showModal();else locationHelpDialog.setAttribute('open','');requestAnimationFrame(()=>document.querySelector('#location-help-title').focus());}
