 const manual=document.createElement('button');manual.type='button';manual.id='choose-location-map';manual.className='location-choice-button';appendText(manual,'span','🗺️ Elegir en el mapa');appendText(manual,'small','Marcar manualmente la parcela');manual.addEventListener('click',()=>openManualLocationMap());actions.append(current,manual);section.append(actions);
