function visualAnalysisAllowed(){return publisherType()==='corredor'&&planIncludesVisualAnalysis(selectedBrokerPlan());}
function updateVisualAnalysisAvailability(){const broker=publisherType()==='corredor',allowed=visualAnalysisAllowed();visualAnalysisUi.option.hidden=!allowed;visualAnalysisUi.unavailable.hidden=!broker||!selectedBrokerPlan()||allowed;visualAnalysisConsent.disabled=!allowed;if(!allowed){visualAnalysisConsent.checked=false;visualAnalysisData=null;visualAnalysisUi.review.hidden=true;}else{visualAnalysisUi.status.textContent=visualAnalysisConsent.checked?'Análisis solicitado. Se usarán como máximo 5 fotografías después de confirmar la contratación.':'Opcional. Puedes publicar sin utilizar el análisis visual.';}document.querySelectorAll('.plan-card').forEach(card=>card.classList.toggle('is-ai-premium',planIncludesVisualAnalysis(card.dataset.planId)));}
function renderVisualAnalysisReview(){const suggestions=visualAnalysisData?.suggestions,visible=visualAnalysisAllowed()&&suggestions&&visualAnalysisData.status!=='rejected';visualAnalysisUi.review.hidden=!visible;if(!visible)return;visualAnalysisUi.description.value=suggestions.description||'';visualAnalysisUi.features.value=Array.isArray(suggestions.visibleFeatures)?suggestions.visibleFeatures.join('\n'):suggestions.visibleFeatures||'';visualAnalysisUi.cover.value=suggestions.coverOrder?String(Number(suggestions.coverOrder)+1):'';visualAnalysisUi.reviewStatus.textContent=visualAnalysisData.status==='accepted'?'Sugerencias aceptadas.':visualAnalysisData.status==='edited'?'Correcciones guardadas.':'Sugerencias pendientes de revisión.';}
