const visitDialog=document.querySelector('#visit-dialog'),visitForm=document.querySelector('#visit-request-form'),visitStatus=document.querySelector('#visit-request-status');document.querySelector('#schedule-visit').addEventListener('click',()=>{currentResponsible=responsibleData();document.querySelector('#visit-responsible-copy').textContent=`Tu solicitud será atendida por ${currentResponsible.responsable_nombre}.`;visitStatus.textContent='';if(typeof visitDialog.showModal==='function')visitDialog.showModal();else visitDialog.setAttribute('open','');});document.querySelector('#close-visit-dialog').addEventListener('click',()=>{if(typeof visitDialog.close==='function')visitDialog.close();else visitDialog.removeAttribute('open');});visitForm.addEventListener('submit',event=>{event.preventDefault();if(!visitForm.checkValidity()){visitForm.reportValidity();return;}currentResponsible=responsibleData();const values=Object.fromEntries(new FormData(visitForm).entries()),request=createVisitRequest({nombre:values.visitanteNombre,telefono:values.visitanteTelefono,correo:values.visitanteCorreo,fechaPreferida:values.fechaPreferida,horario:values.horario,mensaje:values.mensajeVisita},currentResponsible);visitRequests.push(request);try{localStorage.setItem(CURRENT_STORAGE_KEY,JSON.stringify(serializeDraftWithSubmission()));visitStatus.textContent=`Solicitud guardada localmente y asociada a ${currentResponsible.responsable_nombre}.`;visitForm.reset();}catch{visitStatus.textContent='No pudimos guardar la solicitud localmente. Tus datos siguen visibles para que puedas intentarlo nuevamente.';}});
form.addEventListener('submit',async event=>{
  event.preventDefault();
  if(isSubmitting)return;
  if(lastSubmission?.status==='publicado'){renderSubmissionSuccess(lastSubmission);return;}
  if(lastSubmission?.status==='pendiente_revision'){renderSubmissionSuccess(lastSubmission);return;}
  if(!validateSubmission())return;

  // NUEVO: Verificación de Pago de Planes Flow.cl y Parcelas Extra
  const type = publisherType();
  let amountToPay = 0;
  let paymentConcept = '';
  let paymentId = '';
  let customerEmail = '';

  if (type === 'corredor') {
    const planId = selectedBrokerPlan();
    const planObj = BROKER_PLANS.find(p => p.id === planId);
    if (planObj && planObj.price > 0 && !sessionStorage.getItem('tpl_plan_paid_' + planId)) {
      amountToPay = planObj.price;
      paymentConcept = 'Compra de ' + planObj.name + ' - Tu Parcela Lista';
      paymentId = planId;
      customerEmail = form.elements.correoCorredor.value;
    }
  } else if (type === 'dueno') {
    const extraParcels = Math.max(0, parseInt(form.elements.cantidadParcelas?.value || 1) - 1);
    if (extraParcels > 0 && !sessionStorage.getItem('tpl_extra_paid_' + extraParcels)) {
      amountToPay = extraParcels * 5990;
      paymentConcept = 'Pago por ' + extraParcels + ' parcela(s) adicional(es) - Tu Parcela Lista';
      paymentId = 'extra_' + extraParcels;
      customerEmail = form.elements.correoDueno.value;
    }
  }

  if (amountToPay > 0) {
    isSubmitting = true;
    saveButton.disabled = true;
    saveButton.textContent = 'Redirigiendo a Flow.cl para continuar...';
    try {
      const flowRes = await fetch('/api/flow-create', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          amount: amountToPay,
          email: customerEmail || 'contacto@tuparcelalista.cl',
          subject: paymentConcept,
          leadId: 'PAGO-' + paymentId + '-' + Date.now(),
          returnUrl: window.location.href + '?flow=success&paid_feature=' + paymentId
        })
      });
      const flowData = await flowRes.json();
      if (flowData.success && flowData.redirectUrl) {
        localStorage.setItem(CURRENT_STORAGE_KEY,JSON.stringify(serializeDraft()));
        if(type==='corredor') sessionStorage.setItem('tpl_plan_pending', paymentId);
        else sessionStorage.setItem('tpl_extra_pending', paymentId);
        window.location.href = flowData.redirectUrl;
        return;
      } else {
        throw new Error("No se pudo iniciar el pago");
      }
    } catch (err) {
      console.error(err);
      isSubmitting = false;
      saveButton.disabled = false;
      saveButton.textContent = 'Publicar';
      setMessage('Error al conectar con Flow. Intenta nuevamente.');
      return;
    }
  }

  isSubmitting=true;
  saveButton.disabled=true;
  saveButton.textContent='Enviando publicación.';
  saveButton.setAttribute('aria-busy','true');
  setMessage('Enviando publicación.',true);
  try{
    await new Promise(resolve=>setTimeout(resolve,450));
    const baseDraft={...serializeDraft(),submission:lastSubmission||undefined};
    const submittedDraft=await submissionAdapter.submit(baseDraft,{photos:photos.map(photo=>({file:photo.file,cover:photo.id===coverId})),onCheckpoint:checkpoint=>{lastSubmission=checkpoint.submission;localStorage.setItem(CURRENT_STORAGE_KEY,JSON.stringify(checkpoint));}});
    if(beginVisualAnalysisReview(submittedDraft))return;
    lastSubmission=submittedDraft.submission;
    localStorage.setItem(CURRENT_STORAGE_KEY,JSON.stringify(submittedDraft));
    saveButton.textContent='Publicación enviada';
    renderSubmissionSuccess(lastSubmission);
  }catch(error){
    isSubmitting=false;
    if(error?.recoveryDraft){lastSubmission=error.recoveryDraft.submission;localStorage.setItem(CURRENT_STORAGE_KEY,JSON.stringify(error.recoveryDraft));}
    saveButton.disabled=false;
    saveButton.textContent=lastSubmission?.publicationId?'Reintentar publicación':'Publicar';
    setMessage(error?.message||'No fue posible guardar la publicación preparada. Inténtalo nuevamente.');
  }finally{
    saveButton.removeAttribute('aria-busy');
  }
});

populateRegions();renderPlans();setupVoice();createSuccessScreen();restoreDraft();restoreVisualAnalysisState();restoreLocationState();restoreVisitState();updateStoryCount();showStep(1,false);restoreSubmissionState();

// Manejo de retorno de Flow.cl
const urlParams = new URLSearchParams(window.location.search);
if (urlParams.get('flow') === 'success' && urlParams.get('plan')) {
  const planPaid = urlParams.get('plan');
  sessionStorage.setItem(`tpl_plan_paid_${planPaid}`, 'true');
  window.history.replaceState({}, document.title, window.location.pathname);
  setTimeout(() => {
    setMessage(`¡Pago del ${planPaid.toUpperCase()} exitoso! Ahora puedes enviar tu publicación.`, true);
    // Auto-click the submit button again to send it
    saveButton.click();
  }, 1000);
}


// ==========================================
// INYECCIÓN DE LÓGICA IA Y UX
// ==========================================
import { simulateAIEnrichment } from './description-generator.js';

document.addEventListener('DOMContentLoaded', () => {
  const btnAI = document.getElementById('btn-magic-ai');
  if (btnAI) {
    btnAI.addEventListener('click', async () => {
      const planElegido = document.querySelector('input[name="planCorredor"]:checked')?.value;
      const isCorredor = document.querySelector('input[name="tipoPublicador"][value="corredor"]').checked;
      
      // Permitir si es Gold, Platinum, o si pagó el upsell de $7.990 (hasAIPower)
      const isPremiumPlan = isCorredor && (planElegido === 'gold' || planElegido === 'platinum');
      
      if (!isPremiumPlan && !window.hasAIPower && isCorredor) {
        alert('Esta función es exclusiva de los planes Gold/Platinum o el ticket de $7.990. Simula el pago dándole a "Publicar Parcela" con el plan Inicio para probarlo.');
        return;
      }
      
      btnAI.textContent = 'Analizando fotos...';
      btnAI.disabled = true;
      
      // Construir data básica de lo ingresado para mandarla a la IA
      const form = document.getElementById('publication-form');
      const data = {
        superficie: form.elements.superficieMinima?.value || '',
        comuna: document.getElementById('comuna-display')?.textContent || '',
      };
      
      try {
        const result = await simulateAIEnrichment(data, true);
        const descArea = document.getElementById('descripcion-publica');
        if (descArea) {
          descArea.value = result.enrichedDescription;
          descArea.style.border = "2px solid #4f46e5";
          descArea.style.backgroundColor = "rgba(99,102,241,0.05)";
        }
        
        // Simular que encontró la ubicación
        if (window.confirm('La IA detectó una posible ubicación de la parcela basándose en el análisis visual. ¿Deseas aplicar las coordenadas recomendadas?')) {
           const mapInp = document.getElementById('link-google-maps');
           if(mapInp) mapInp.value = 'https://maps.google.com/?q=' + result.suggestedCoordinates.latitude + ',' + result.suggestedCoordinates.longitude;
        }
        
      } catch(e) {
        console.error(e);
      } finally {
        btnAI.textContent = '✨ Enriquecido con IA';
        btnAI.style.background = '#10b981';
      }
    });
  }
  
  // Simulación Visual de Sugerencia de Foto de Portada
  const dropZone = document.getElementById('photo-drop-zone');
  const aiBadge = document.getElementById('ai-photo-suggestion');
  if (dropZone && aiBadge) {
    const observer = new MutationObserver(() => {
      // Si hay fotos, mostrar el badge simulando análisis
      if (dropZone.querySelectorAll('.photo-thumbnail').length > 0) {
        aiBadge.style.display = 'block';
      } else {
        aiBadge.style.display = 'none';
      }
    });
    observer.observe(dropZone, { childList: true });
  }
});
